const config = $('Get Agent Config').first().json;

const agentConfig = config.agent_config || {};
const playbooks = config.playbooks || [];
const escalationRules = config.escalation_rules || [];

// Build playbooks text for routing
let playbooksText = '';
for (const pb of playbooks) {
  playbooksText += `ID: ${pb.id}\n`;
  playbooksText += `Title: ${pb.title}\n`;
  playbooksText += `Audience: ${pb.audience || 'N/A'}\n`;
  playbooksText += `Rules: ${pb.rules || 'N/A'}\n`;
  playbooksText += `---\n`;
}

// Build escalation rules text for routing
let escalationRulesText = '';
for (const er of escalationRules) {
  escalationRulesText += `ID: ${er.id}\n`;
  escalationRulesText += `Title: ${er.title}\n`;
  escalationRulesText += `Audience: ${er.audience || 'N/A'}\n`;
  escalationRulesText += `Trigger: ${er.trigger_description || 'N/A'}\n`;
  escalationRulesText += `Rules: ${er.rules || 'N/A'}\n`;
  escalationRulesText += `---\n`;
}

return [{
  json: {
    agent_config: agentConfig,
    playbooks,
    escalation_rules: escalationRules,
    playbooks_text: playbooksText,
    escalation_rules_text: escalationRulesText
  }
}];

const config = $('Get Agent Config').first().json;
const playbooks = config.playbooks || [];
const routingOutput = $input.first().json.output;
const activeId = routingOutput.id;

// Find by integer or string ID
const activePlaybook = playbooks.find(pb => String(pb.id) === String(activeId));

if (!activePlaybook) {
  return [{ json: {
    activeType: "scenario",
    activeId,
    activePlaybook: null,
    activeTool: null,
    error: "Playbook not found for ID: " + activeId
  } }];
}

return [{ json: {
  activeType: "scenario",
  activeId,
  activePlaybook,
  activeTool: activePlaybook.tool || null
} }];

const config = $('Get Agent Config').first().json;
const escalationRules = config.escalation_rules || [];
const routingOutput = $input.first().json.output;
const activeId = routingOutput.id;

const activeRule = escalationRules.find(er => String(er.id) === String(activeId));

if (!activeRule) {
  return [{ json: {
    activeType: "escalation",
    activeId,
    activeRule: null,
    error: "Escalation rule not found for ID: " + activeId
  } }];
}

return [{ json: {
  activeType: "escalation",
  activeId,
  activeRule
} }];

