// Create or find session, then log user input + agent output
const webhook = $('Webhook').first().json.body;
const config = $('Get Agent Config').first().json;
const playbook = $('Load Active Playbook').first().json;
const agentOutput = $('Playbook Agent').first().json.output;
const apiKey = $env.AGENT_API_KEY;
const baseUrl = 'https://app.cardynal.io';

// 1. Create or find session
const sessionRes = await fetch(`${baseUrl}/api/agent/sessions`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey },
  body: JSON.stringify({
    user_id: config.user_id,
    inbox_id: null,
    chatwoot_account_id: webhook.account?.id,
    chatwoot_inbox_id: webhook.conversation?.messages?.[0]?.inbox_id,
    chatwoot_conversation_id: webhook.conversation?.messages?.[0]?.conversation_id,
  })
});
const sessionData = await sessionRes.json();
const sessionId = sessionData.session?.id;

if (!sessionId) {
  return [{ json: { error: 'Failed to create session', details: sessionData } }];
}

// 2. Log user message
await fetch(`${baseUrl}/api/agent/messages`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey },
  body: JSON.stringify({
    session_id: sessionId,
    user_id: config.user_id,
    role: 'user',
    content: webhook.conversation?.messages?.[0]?.content || '',
    playbook_id: playbook.activeId ? parseInt(playbook.activeId) : null,
  })
});

// 3. Log agent response
await fetch(`${baseUrl}/api/agent/messages`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey },
  body: JSON.stringify({
    session_id: sessionId,
    user_id: config.user_id,
    role: 'assistant',
    content: agentOutput,
    playbook_id: playbook.activeId ? parseInt(playbook.activeId) : null,
  })
});

return [{ json: { session_id: sessionId, logged: true } }];

// Create session + log messages for escalation
const webhook = $('Webhook').first().json.body;
const config = $('Get Agent Config').first().json;
const escalation = $('Load Escalation Rule').first().json;
const agentOutput = $('Escalation Agent').first().json.output;
const apiKey = $env.AGENT_API_KEY;
const baseUrl = 'https://app.cardynal.io';

// 1. Create or find session
const sessionRes = await fetch(`${baseUrl}/api/agent/sessions`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey },
  body: JSON.stringify({
    user_id: config.user_id,
    inbox_id: null,
    chatwoot_account_id: webhook.account?.id,
    chatwoot_inbox_id: webhook.conversation?.messages?.[0]?.inbox_id,
    chatwoot_conversation_id: webhook.conversation?.messages?.[0]?.conversation_id,
  })
});
const sessionData = await sessionRes.json();
const sessionId = sessionData.session?.id;

if (!sessionId) {
  return [{ json: { error: 'Failed to create session', details: sessionData } }];
}

// 2. Log user message
await fetch(`${baseUrl}/api/agent/messages`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey },
  body: JSON.stringify({
    session_id: sessionId,
    user_id: config.user_id,
    role: 'user',
    content: webhook.conversation?.messages?.[0]?.content || '',
    escalation_id: escalation.activeId ? parseInt(escalation.activeId) : null,
  })
});

// 3. Log escalation response
await fetch(`${baseUrl}/api/agent/messages`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey },
  body: JSON.stringify({
    session_id: sessionId,
    user_id: config.user_id,
    role: 'assistant',
    content: agentOutput.reponse || '',
    escalation_id: escalation.activeId ? parseInt(escalation.activeId) : null,
    metadata: { resume: agentOutput.resume || '' },
  })
});

// 4. Mark session as closed + escalated
await fetch(`${baseUrl}/api/agent/sessions/${sessionId}`, {
  method: 'PUT',
  headers: { 'Content-Type': 'application/json', 'x-api-key': apiKey },
  body: JSON.stringify({
    status: 'closed',
    ai_reason: 'ESCALATION: ' + (agentOutput.resume || ''),
    billable: false,
    closed_at: new Date().toISOString(),
  })
});

return [{ json: { session_id: sessionId, escalated: true } }];
